async function getSites() {
  console.log('Querying Wix Sites API...');
  try {
    const res = await fetch('https://www.wixapis.com/site-list/v2/sites/query', {
      method: 'POST',
      headers: {
        'Authorization': apiKey,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({})
    });
    
    console.log('Wix Sites Query Response status:', res.status);
    const json = await res.json();
    console.log('Sites:', JSON.stringify(json, null, 2));
  } catch (err) {
    console.error('Error fetching sites:', err);
  }
}

getSites();

